"use client";

import { useState, useRef, useEffect } from "react";
import Link from "next/link";
import StepShell from "@/components/StepShell";
import { getRandomComplete, getRandomEncourage, triggerShake } from "@/lib/learningMessages";

export default function TransformPage() {
  const [step, setStep] = useState(0); // 0,1,2 = 三道练习; 3 = 完成
  const [input1, setInput1] = useState("");
  const [input2, setInput2] = useState("");
  const [input3, setInput3] = useState("");
  const [feedback1, setFeedback1] = useState<"idle" | "correct" | "wrong">("idle");
  const [feedback2, setFeedback2] = useState<"idle" | "correct" | "wrong">("idle");
  const [feedback3, setFeedback3] = useState<"idle" | "correct" | "wrong">("idle");
  const [completeMsg, setCompleteMsg] = useState("");
  useEffect(() => { setCompleteMsg(getRandomComplete()); }, []);

  const ref1 = useRef<HTMLInputElement>(null);
  const ref2 = useRef<HTMLInputElement>(null);
  const ref3 = useRef<HTMLInputElement>(null);

  const handleSubmit1 = () => {
    const val = parseInt(input1.trim());
    if (val === 48) {
      setFeedback1("correct");
      setTimeout(() => setStep(1), 1800);
    } else {
      setFeedback1("wrong");
      triggerShake(ref1.current);
      setInput1("");
      setTimeout(() => setFeedback1("idle"), 600);
    }
  };

  const handleSubmit2 = () => {
    const val = parseInt(input2.trim());
    if (val === 65) {
      setFeedback2("correct");
      setTimeout(() => setStep(2), 1800);
    } else {
      setFeedback2("wrong");
      triggerShake(ref2.current);
      setInput2("");
      setTimeout(() => setFeedback2("idle"), 600);
    }
  };

  const handleSubmit3 = () => {
    const val = parseInt(input3.trim());
    if (val === 87) {
      setFeedback3("correct");
      setTimeout(() => setStep(3), 1800);
    } else {
      setFeedback3("wrong");
      triggerShake(ref3.current);
      setInput3("");
      setTimeout(() => setFeedback3("idle"), 600);
    }
  };

  return (
    <StepShell topicId="division" stepId="transform">
      <div className="space-y-5">
        {/* 完成 */}
        {step === 3 && (
          <section className="animate-float-in rounded-[var(--radius)] border-2 border-[var(--signal-success)] bg-[var(--bg-card)] p-6 text-center shadow-[var(--shadow-md)]">
            <div className="text-5xl animate-bounce-soft">🏆</div>
            <h2 className="mt-3 text-xl font-bold text-[var(--text)]">
              {completeMsg}
            </h2>
            <p className="mt-2 text-sm text-[var(--text-secondary)]">
              你已经掌握了除法的验算方法！
            </p>

            {/* 公式卡片 */}
            <div className="mx-auto mt-6 max-w-xs rounded-xl border-2 border-[var(--primary)] bg-[var(--primary)]/10 p-5">
              <p className="text-center text-sm font-bold text-[var(--text)]">
                验算公式
              </p>
              <p className="mt-2 text-center text-xl font-extrabold text-[var(--primary)]">
                商 x 除数 + 余数 = 被除数
              </p>
              <p className="mt-2 text-center text-xs text-[var(--text-secondary)]">
                没有余数时：商 x 除数 = 被除数
              </p>
            </div>

            <div className="mt-6 flex flex-wrap justify-center gap-3">
              <button
                onClick={() => {
                  setStep(0);
                  setInput1("");
                  setInput2("");
                  setInput3("");
                  setFeedback1("idle");
                  setFeedback2("idle");
                  setFeedback3("idle");
                }}
                className="rounded-full border border-[var(--border)] bg-[var(--bg-card)] px-5 py-2 text-sm font-medium text-[var(--text-secondary)] transition-colors hover:bg-[var(--bg-soft)]"
              >
                再练一次
              </button>
              <Link
                href="/learn/division/apply"
                className="rounded-full bg-[var(--accent)] px-6 py-2 text-sm font-bold text-white shadow-[var(--shadow-accent)] transition-all hover:-translate-y-0.5"
              >
                下一步：用一用 →
              </Link>
            </div>
          </section>
        )}

        {/* 练习 1: 48 ÷ 2 = 24, 验算 24 × 2 = ? */}
        {step === 0 && (
          <section className="animate-float-in rounded-[var(--radius)] border border-[var(--border)] bg-[var(--bg-card)] p-6 shadow-[var(--shadow-sm)]">
            {/* 标题 */}
            <div className="text-center">
              <p className="text-sm font-bold text-[var(--accent)]">练习 1 / 3</p>
              <h2 className="mt-1 text-xl font-bold text-[var(--text)]">
                验算没有余数的除法
              </h2>
            </div>

            {/* 除法算式展示 */}
            <div className="mt-5 rounded-xl bg-[var(--bg-soft)] p-5">
              <div className="text-center">
                <p className="text-sm text-[var(--text-secondary)]">除法算式</p>
                <p className="mt-1 text-2xl font-extrabold text-[var(--text)]">
                  48 ÷ 2 = 24
                </p>
              </div>

              {/* 竖式展示 */}
              <div className="mt-4 flex justify-center">
                <div className="rounded-lg border border-[var(--border)] bg-white p-3">
                  <svg viewBox="0 0 120 100" className="h-20 w-24">
                    {/* 除号 */}
                    <text x="0" y="20" fontSize="14" fill="var(--text)" textAnchor="middle">4</text>
                    <text x="0" y="35" fontSize="14" fill="var(--text)" textAnchor="middle">8</text>
                    <text x="0" y="50" fontSize="14" fill="var(--text)" textAnchor="middle">-</text>
                    <text x="0" y="63" fontSize="14" fill="var(--text)" textAnchor="middle">8</text>
                    <line x1="0" y1="65" x2="40" y2="65" stroke="var(--text)" strokeWidth="1.5"/>
                    <text x="0" y="80" fontSize="14" fill="var(--text)" textAnchor="middle">0</text>
                    {/* 除号弧线 */}
                    <path d="M -8 10 L 0 10 L 12 55 L 0 55" fill="none" stroke="var(--text)" strokeWidth="1.5"/>
                    {/* 除数 */}
                    <text x="20" y="50" fontSize="14" fill="var(--primary)" fontWeight="bold" textAnchor="middle">2</text>
                  </svg>
                </div>
              </div>
            </div>

            {/* 验算提示 */}
            <div className="mt-5 rounded-xl border border-[var(--accent)] bg-[var(--accent)]/10 p-4">
              <p className="text-center text-sm font-bold text-[var(--text)]">
                用乘法验算：商 x 除数 = 被除数
              </p>
            </div>

            {/* 输入区域 */}
            <div className="mt-5 flex flex-col items-center gap-3">
              <p className="text-sm text-[var(--text-secondary)]">
                请填写：24 x 2 = ?
              </p>
              <div className="flex items-center gap-2">
                <span className="text-lg font-bold text-[var(--text)]">24 x 2 =</span>
                <input
                  ref={ref1}
                  type="number"
                  value={input1}
                  onChange={(e) => setInput1(e.target.value)}
                  onKeyDown={(e) => e.key === "Enter" && handleSubmit1()}
                  placeholder="?"
                  className="w-20 rounded-xl border-2 border-[var(--border)] bg-white px-4 py-2 text-center text-lg font-bold text-[var(--text)] outline-none transition-colors focus:border-[var(--primary)]"
                />
              </div>
              <button
                onClick={handleSubmit1}
                className="rounded-full bg-[var(--accent)] px-6 py-2.5 text-sm font-bold text-white shadow-[var(--shadow-accent)] transition-all hover:-translate-y-0.5 hover:shadow-[var(--shadow-md)]"
              >
                提交验证
              </button>
            </div>

            {/* 反馈 */}
            {feedback1 === "correct" && (
              <div className="mt-4 animate-float-in rounded-xl border-2 border-[var(--signal-success)] bg-[var(--signal-success)]/10 p-4 text-center">
                <p className="font-bold text-[var(--signal-success)]">
                  验算正确！24 x 2 = 48，和被除数一样！
                </p>
              </div>
            )}
            {feedback1 === "wrong" && (
              <div className="mt-4 animate-float-in rounded-xl border-2 border-[var(--border)] bg-[var(--bg-soft)] p-4 text-center">
                <p className="text-sm text-[var(--text-secondary)]">
                  {getRandomEncourage()}
                </p>
              </div>
            )}
          </section>
        )}

        {/* 练习 2: 65 ÷ 3 = 21...2, 验算 21 × 3 + 2 = ? */}
        {step === 1 && (
          <section className="animate-float-in rounded-[var(--radius)] border border-[var(--border)] bg-[var(--bg-card)] p-6 shadow-[var(--shadow-sm)]">
            {/* 标题 */}
            <div className="text-center">
              <p className="text-sm font-bold text-[var(--primary)]">练习 2 / 3</p>
              <h2 className="mt-1 text-xl font-bold text-[var(--text)]">
                验算有余数的除法
              </h2>
            </div>

            {/* 除法算式展示 */}
            <div className="mt-5 rounded-xl bg-[var(--bg-soft)] p-5">
              <div className="text-center">
                <p className="text-sm text-[var(--text-secondary)]">除法算式</p>
                <p className="mt-1 text-2xl font-extrabold text-[var(--text)]">
                  65 ÷ 3 = 21 ... 2
                </p>
              </div>

              {/* 竖式展示 */}
              <div className="mt-4 flex justify-center">
                <div className="rounded-lg border border-[var(--border)] bg-white p-3">
                  <svg viewBox="0 0 140 110" className="h-24 w-28">
                    <text x="0" y="20" fontSize="14" fill="var(--text)" textAnchor="middle">6</text>
                    <text x="0" y="35" fontSize="14" fill="var(--text)" textAnchor="middle">5</text>
                    <text x="0" y="50" fontSize="14" fill="var(--text)" textAnchor="middle">-</text>
                    <text x="0" y="63" fontSize="14" fill="var(--text)" textAnchor="middle">6</text>
                    <line x1="0" y1="65" x2="40" y2="65" stroke="var(--text)" strokeWidth="1.5"/>
                    <text x="0" y="80" fontSize="14" fill="var(--text)" textAnchor="middle">0</text>
                    <text x="0" y="95" fontSize="14" fill="var(--text)" textAnchor="middle">5</text>
                    <text x="0" y="108" fontSize="14" fill="var(--text)" textAnchor="middle">-</text>
                    <path d="M -8 10 L 0 10 L 12 60 L 0 60" fill="none" stroke="var(--text)" strokeWidth="1.5"/>
                    <text x="20" y="50" fontSize="14" fill="var(--primary)" fontWeight="bold" textAnchor="middle">3</text>
                  </svg>
                </div>
              </div>
            </div>

            {/* 验算提示 */}
            <div className="mt-5 rounded-xl border border-[var(--primary)] bg-[var(--primary)]/10 p-4">
              <p className="text-center text-sm font-bold text-[var(--text)]">
                有余数的验算：商 x 除数 + 余数 = 被除数
              </p>
            </div>

            {/* 输入区域 */}
            <div className="mt-5 flex flex-col items-center gap-3">
              <p className="text-sm text-[var(--text-secondary)]">
                请填写：21 x 3 + 2 = ?
              </p>
              <div className="flex items-center gap-2">
                <span className="text-lg font-bold text-[var(--text)]">21 x 3 + 2 =</span>
                <input
                  ref={ref2}
                  type="number"
                  value={input2}
                  onChange={(e) => setInput2(e.target.value)}
                  onKeyDown={(e) => e.key === "Enter" && handleSubmit2()}
                  placeholder="?"
                  className="w-20 rounded-xl border-2 border-[var(--border)] bg-white px-4 py-2 text-center text-lg font-bold text-[var(--text)] outline-none transition-colors focus:border-[var(--primary)]"
                />
              </div>
              <button
                onClick={handleSubmit2}
                className="rounded-full bg-[var(--primary)] px-6 py-2.5 text-sm font-bold text-white shadow-[var(--shadow-sm)] transition-all hover:-translate-y-0.5 hover:shadow-[var(--shadow-md)]"
              >
                提交验证
              </button>
            </div>

            {/* 反馈 */}
            {feedback2 === "correct" && (
              <div className="mt-4 animate-float-in rounded-xl border-2 border-[var(--signal-success)] bg-[var(--signal-success)]/10 p-4 text-center">
                <p className="font-bold text-[var(--signal-success)]">
                  验算正确！商 x 除数 + 余数 = 被除数
                </p>
                <p className="mt-1 text-sm text-[var(--text-secondary)]">
                  21 x 3 + 2 = 65，正好等于被除数！
                </p>
              </div>
            )}
            {feedback2 === "wrong" && (
              <div className="mt-4 animate-float-in rounded-xl border-2 border-[var(--border)] bg-[var(--bg-soft)] p-4 text-center">
                <p className="text-sm text-[var(--text-secondary)]">
                  {getRandomEncourage()}
                </p>
              </div>
            )}
          </section>
        )}

        {/* 练习 3: 87 ÷ 4 = 21...3, 验算 21 × 4 + 3 = ? */}
        {step === 2 && (
          <section className="animate-float-in rounded-[var(--radius)] border border-[var(--border)] bg-[var(--bg-card)] p-6 shadow-[var(--shadow-sm)]">
            {/* 标题 */}
            <div className="text-center">
              <p className="text-sm font-bold text-[var(--accent2)]">练习 3 / 3</p>
              <h2 className="mt-1 text-xl font-bold text-[var(--text)]">
                自己来验算
              </h2>
            </div>

            {/* 除法算式展示 */}
            <div className="mt-5 rounded-xl bg-[var(--bg-soft)] p-5">
              <div className="text-center">
                <p className="text-sm text-[var(--text-secondary)]">除法算式</p>
                <p className="mt-1 text-2xl font-extrabold text-[var(--text)]">
                  87 ÷ 4 = 21 ... 3
                </p>
              </div>

              {/* 竖式展示 */}
              <div className="mt-4 flex justify-center">
                <div className="rounded-lg border border-[var(--border)] bg-white p-3">
                  <svg viewBox="0 0 140 110" className="h-24 w-28">
                    <text x="0" y="20" fontSize="14" fill="var(--text)" textAnchor="middle">8</text>
                    <text x="0" y="35" fontSize="14" fill="var(--text)" textAnchor="middle">7</text>
                    <text x="0" y="50" fontSize="14" fill="var(--text)" textAnchor="middle">-</text>
                    <text x="0" y="63" fontSize="14" fill="var(--text)" textAnchor="middle">8</text>
                    <line x1="0" y1="65" x2="40" y2="65" stroke="var(--text)" strokeWidth="1.5"/>
                    <text x="0" y="80" fontSize="14" fill="var(--text)" textAnchor="middle">0</text>
                    <text x="0" y="95" fontSize="14" fill="var(--text)" textAnchor="middle">7</text>
                    <text x="0" y="108" fontSize="14" fill="var(--text)" textAnchor="middle">-</text>
                    <path d="M -8 10 L 0 10 L 12 60 L 0 60" fill="none" stroke="var(--text)" strokeWidth="1.5"/>
                    <text x="20" y="50" fontSize="14" fill="var(--accent2)" fontWeight="bold" textAnchor="middle">4</text>
                  </svg>
                </div>
              </div>
            </div>

            {/* 验算提示 */}
            <div className="mt-5 rounded-xl border border-[var(--accent2)] bg-[var(--accent2)]/10 p-4">
              <p className="text-center text-sm font-bold text-[var(--text)]">
                试着自己写出验算过程
              </p>
            </div>

            {/* 输入区域 */}
            <div className="mt-5 flex flex-col items-center gap-3">
              <p className="text-sm text-[var(--text-secondary)]">
                请填写：21 x 4 + 3 = ?
              </p>
              <div className="flex items-center gap-2">
                <span className="text-lg font-bold text-[var(--text)]">21 x 4 + 3 =</span>
                <input
                  ref={ref3}
                  type="number"
                  value={input3}
                  onChange={(e) => setInput3(e.target.value)}
                  onKeyDown={(e) => e.key === "Enter" && handleSubmit3()}
                  placeholder="?"
                  className="w-20 rounded-xl border-2 border-[var(--border)] bg-white px-4 py-2 text-center text-lg font-bold text-[var(--text)] outline-none transition-colors focus:border-[var(--primary)]"
                />
              </div>
              <button
                onClick={handleSubmit3}
                className="rounded-full bg-[var(--accent2)] px-6 py-2.5 text-sm font-bold text-white shadow-[var(--shadow-sm)] transition-all hover:-translate-y-0.5 hover:shadow-[var(--shadow-md)]"
              >
                提交验证
              </button>
            </div>

            {/* 反馈 */}
            {feedback3 === "correct" && (
              <div className="mt-4 animate-float-in rounded-xl border-2 border-[var(--signal-success)] bg-[var(--signal-success)]/10 p-4 text-center">
                <p className="font-bold text-[var(--signal-success)]">
                  验算正确！21 x 4 + 3 = 87！
                </p>
              </div>
            )}
            {feedback3 === "wrong" && (
              <div className="mt-4 animate-float-in rounded-xl border-2 border-[var(--border)] bg-[var(--bg-soft)] p-4 text-center">
                <p className="text-sm text-[var(--text-secondary)]">
                  {getRandomEncourage()}
                </p>
              </div>
            )}
          </section>
        )}
      </div>
    </StepShell>
  );
}
